  "comparisons": [
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "c9_oyster_spat_poles",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 có nhịp độ tốt hơn và cơ chế 'làm giàu bằng tay nghề' rõ rệt hơn. Trong khi c9 phải đợi hàu lớn (mất nhiều tháng) và phải dùng việc bắt cá đối để lấp chỗ trống, c7 tạo ra vòng lặp thu mua - vận chuyển - bán hàng ngay từ chương 2. Kỹ thuật chế sục khí từ bơm xe đạp rất sáng tạo và phù hợp với bối cảnh thiếu thốn cuối thập niên 80."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "c10_net_modifications",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 thắng nhờ tính chủ động (agency) cao hơn. Nhân vật chính trong c7 tự mình vận hành cả chuỗi cung ứng từ thu mua đến bán lẻ, trong khi c10 thiên về cung cấp dịch vụ sửa chữa thụ động. Vòng thưởng của c7 (tiền lời từ hải sản sống) mạnh mẽ và dễ mở rộng quy mô hơn việc chỉ đi vá lưới thuê."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_01",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 tập trung vào một thị trường ngách có giá trị cao (hải sản sống) và giải quyết nó bằng kỹ thuật cơ khí, mang lại cảm giác 'nam tần' mạnh mẽ hơn. dt_01_01 thiên về ẩm thực, dù ấm áp nhưng quy mô làm giàu và sự đột phá về công cụ không ấn tượng bằng hệ thống sục khí thủ công của c7."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_02",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 đạt được thành quả sớm (chương 3 có tiền mua áo cho vợ) một cách tự nhiên. dt_01_02 về làm mắm có độ trễ thời gian lên men rất lớn, việc 'cứu mẻ mắm hỏng' ở chương 3 tuy hợp lý nhưng không tạo ra sự bùng nổ về kinh tế và khoái hoạt bằng việc đưa được bề bề sống lên tỉnh bán giá cao."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_03",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 có cơ chế vận hành độc đáo hơn. Việc kết hợp giữa thể lực (đạp xe 20km) và kỹ thuật (sục khí liên tục) tạo ra một 'chi phí thật' rất thuyết phục. dt_01_03 tương tự c10, tập trung vào sửa chữa lưới, thiếu đi sự kịch tính của việc vận chuyển hàng tươi sống đối đầu với thời gian."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_04",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 thắng do giá trị kinh tế của sản phẩm rõ ràng hơn. Rong biển trong dt_01_04 là một mặt hàng khó tạo ra sự giàu có nhanh chóng trong bối cảnh năm 1988 so với hải sản cao cấp sống. Cơ chế sục khí của c7 cũng thể hiện tư duy 'độ chế' đặc trưng của thời đại tốt hơn."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_05",
      "winnerId": "dt_01_concept_05",
      "reason": "dt_01_05 thắng vì nhận diện được 'điểm nghẽn' lớn nhất của toàn ngành cá thời bấy giờ là bảo quản lạnh. Việc dùng trấu và xơ dừa làm hầm đá là một chi tiết nghiên cứu thực tế rất tốt, tạo ra tác động kinh tế sâu rộng hơn cho cả làng chài thay vì chỉ là một cá nhân đi buôn như c7."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_06",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 có tính seriality tốt hơn. Việc vận chuyển hải sản có thể biến hóa qua nhiều loại hàng và nâng cấp phương tiện (xe đạp lên xe lam, xe tải). dt_01_06 về thiết kế tàu thuyền có bước nhảy vọt lớn nhưng khó duy trì nhịp độ 'mẻ hàng/bữa cơm' liên tục mỗi chương do đóng tàu là quá trình dài."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_07",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 thắng nhờ cơ chế kỹ thuật (oxy cơ học) thú vị hơn là tư duy marketing của dt_01_07
